var e=[{id:`L2_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......죄송해요, 선배님.`,JPN:`……ごめんなさい、先輩。`,ENG:`I'm sorry.`,TWN:`……對不起，前輩。`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`하지만 이것도 경기의 규칙이니까요.`,JPN:`でもこれも試合のルールだから。`,ENG:`But this is also part of the game.`,TWN:`不過這也是比賽的規則。`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......이, 이얏!`,JPN:`……え、えいっ！`,ENG:`E-eeyap!`,TWN:`……咿，咿呀！`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`그래! 결국 먼저 골에 들어가는 건 나......!`,JPN:`そう！　先にゴールインするのは私……！`,ENG:`That's right! I'm still coming in first—`,TWN:`是了！冠軍終究是我……！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_SERIOUS`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`앗?! 뭐야, 이 깡통!?`,JPN:`え！？　なに、この缶は！？`,ENG:`Wah! What's this can doing here?`,TWN:`啊？！什麼，這個飲料罐！？`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_SURPRISE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`이, 이건......`,JPN:`こ、これは……`,ENG:`Th-this...`,TWN:`這，這……`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`이건 사기야! 대체 누가 여기에 음료수 캔을 가져다 둔 거냐고!`,JPN:`これは罠よ！　いったい誰がこんなところに缶を置いたの！？`,ENG:`This is rigged! Somebody left the soda can here on purpose!`,TWN:`這是耍詐！究竟是誰把飲料罐放在這裡的！`},stage:{bg:`SKY`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`......어라?`,JPN:`……あれ？`,ENG:`Err?`,TWN:`……咦？`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`선수들한테 나눠 줄 음료수가 하나 비는데? 어디 갔지?`,JPN:`選手たちに配る飲み物が1個足りない！　どこに消えたんだろう？`,ENG:`I seem to be missing one soda can from my stash. Where did it go?`,TWN:`要發給選手們的飲料怎麼少了一個？放哪裡了？`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`......말도 없이 빌려가서 죄송해요.`,JPN:`……何も言わずに借りてごめんなさい。`,ENG:`I'm sorry I borrowed it without telling you.`,TWN:`……對不起，我擅自借用了一下。`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_DESPAIR`},C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`RULER_JUNIOR_NULL_NULL`,text:{KOREA:`여기 가져다 놓을게요.`,JPN:`ここに戻しておくね。`,ENG:`I've brought it back.`,TWN:`我這就去拿回來。`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`RULER_JUNIOR_NULL_NULL`,face:`UNIT_IDLE`},C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`아! 찾았다!`,JPN:`あ！　見つけた！`,ENG:`Ah, there it is!`,TWN:`啊！找到了！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`으...... 근데 그새 누가 밟고 갔나 보네. 캔이 다 찌그러졌어.`,JPN:`うーん……でも誰かに踏まれたのかな。缶が潰れているわ。`,ENG:`Ack, but who stepped on it? It's all crushed.`,TWN:`呃……不過好像被誰給踩了，飲料罐都變形了。`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`할 수 없네. 그냥 새로 하나 더 가져와야겠다.`,JPN:`仕方ないわね。新しいものを持ってこよう。`,ENG:`Oh well, I'm just going to get a new one.`,TWN:`沒辦法了，只能再去拿一個新的了。`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`......어라?`,JPN:`……あれ？`,ENG:`Huh?`,TWN:`……咦？`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`HOJIN_REBBIT_NULL_NULL`,text:{KOREA:`거기 너! 잠시만!`,JPN:`そこの君！　待って！`,ENG:`Hey, you! Wait!`,TWN:`喂，你！等等！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`HOJIN_REBBIT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};